class UniverseUILogger {
  private _scope: string;
  constructor(option: { scope: string }) {
    this._scope = option.scope;
  }

  formatMessage(message: unknown, style?: string) {
    return [`%c [${this._scope}] ${message}`, style];
  }

  info(message?: unknown, ...optionalParams: unknown[]) {
    return console.log(...this.formatMessage(message), ...optionalParams);
  }

  warn(message?: unknown, ...optionalParams: unknown[]) {
    return console.warn(...this.formatMessage(message), ...optionalParams);
  }

  error(message?: unknown, ...optionalParams: unknown[]) {
    return console.error(...this.formatMessage(message), ...optionalParams);
  }

  debug(message?: unknown, ...optionalParams: unknown[]) {
    return console.debug(...this.formatMessage(message), ...optionalParams);
  }
}

export const logger = new UniverseUILogger({
  scope: 'UD',
});
